external_knowledge:
- 'Crème de la crème' refers to the best of the best; 
- 'thirst for the game' implies a high level of participation, in this case, more than 50 games played;
- 'latest season' refers to the most recent year found in the 'season' column of the 'player_stats' table.

sql:
SELECT name
FROM players
WHERE player_id IN (
  SELECT player_id
  FROM trades
);

SELECT name, hits AS total_hits
FROM players
WHERE player_id = 1;
